const errData = $input.first().json;
const workflowId = errData.workflow?.id || 'unknown';
const workflowName = errData.workflow?.name || 'Unknown Workflow';
const errorMessage = errData.execution?.error?.message || 'Unknown error';
const errorStack = errData.execution?.error?.stack || '';
const lastNode = errData.execution?.lastNodeExecuted || 'Unknown';
const executionId = errData.execution?.id || 'unknown';
const executionMode = errData.execution?.mode || 'unknown';

return [{
  json: {
    workflowId,
    workflowName,
    errorMessage,
    errorStack,
    lastNode,
    executionId,
    executionMode,
    errorSummary: `Workflow "${workflowName}" (${workflowId}) failed at node "${lastNode}". Error: ${errorMessage}`
  }
}];

// Get error context from earlier in the chain
const allItems = $input.all();
const workflowJson = allItems[0].json;

// Get error context from the first node's output (passed via $('Extract Error Info'))
const errorContext = $('Extract Error Info').first().json;

// Only extract essential workflow parts to keep prompt manageable
const essentialWorkflow = {
  id: workflowJson.id,
  name: workflowJson.name,
  nodes: workflowJson.nodes,
  connections: workflowJson.connections,
  settings: workflowJson.settings
};

const prompt = `You are an expert n8n workflow repair specialist. A workflow has errored and you must fix it.

ERROR DETAILS:
- Workflow: "${errorContext.workflowName}" (ID: ${errorContext.workflowId})
- Failed at node: "${errorContext.lastNode}"
- Error message: ${errorContext.errorMessage}
- Stack trace: ${errorContext.errorStack?.substring(0, 500) || 'N/A'}

CURRENT WORKFLOW JSON:
${JSON.stringify(essentialWorkflow, null, 2).substring(0, 8000)}

YOUR TASK:
1. Analyze the error and identify the root cause
2. Fix the issue in the workflow nodes/connections
3. Return ONLY a valid JSON object with this exact structure:
{
  "analysis": "Brief explanation of what was wrong",
  "fix_applied": "Brief description of what you fixed",
  "nodes": [...fixed nodes array...],
  "connections": {...fixed connections...}
}

IMPORTANT: The nodes and connections arrays must be complete and valid n8n workflow format.`;

return [{ json: { 
  prompt, 
  workflowId: errorContext.workflowId,
  workflowName: errorContext.workflowName,
  errorMessage: errorContext.errorMessage,
  lastNode: errorContext.lastNode
}}];

const response = $input.first().json;
const content = response.content?.[0]?.text || '';

// Extract JSON from Claude's response
let fixData;
try {
  // Try to find JSON block in response
  const jsonMatch = content.match(/\{[\s\S]*"nodes"[\s\S]*"connections"[\s\S]*\}/);
  if (jsonMatch) {
    fixData = JSON.parse(jsonMatch[0]);
  } else {
    fixData = JSON.parse(content);
  }
} catch(e) {
  // If parsing fails, return error info
  return [{ json: { 
    success: false, 
    error: 'Could not parse Claude response: ' + e.message,
    rawResponse: content.substring(0, 500)
  }}];
}

// Get context from previous nodes
const context = $('Prepare Fix Prompt').first().json;

return [{ json: {
  success: true,
  workflowId: context.workflowId,
  workflowName: context.workflowName,
  analysis: fixData.analysis || 'Analysis not provided',
  fix_applied: fixData.fix_applied || 'Fix not described',
  nodes: fixData.nodes,
  connections: fixData.connections,
  originalError: context.errorMessage
}}];

const fixData = $('Parse Claude Fix').first().json;
const republishResult = $input.first().json;

const status = republishResult.active ? '✅ Auto-fixed and republished' : '⚠️ Fix applied but republish status unknown';

return [{ json: {
  notification: `🔧 *ASAR Auto-Heal Triggered*\n\n*Workflow:* ${fixData.workflowName}\n*Status:* ${status}\n*Root Cause:* ${fixData.analysis}\n*Fix Applied:* ${fixData.fix_applied}\n*Original Error:* ${fixData.originalError}`,
  workflowName: fixData.workflowName,
  status,
  analysis: fixData.analysis
}}];

